onClick:
{{
AddPartTypeSelect.value === "cpu"
  ? CreateCPU.run()
      .then(() => {
        closeModal("AddPartModal");
        GetCPU.run();
        showAlert("CPU created successfully", "success");
      })
      .catch((err) => {
        showAlert("Failed to create CPU", "error");
        console.log(err);
      })
